INSERT INTO public.danh_muc_dich_vu (id, ten_danh_muc, mo_ta, thu_tu_hien_thi, an_hien, loai_danh_muc) VALUES (21, 'Phục Hồi Cơ & Giảm Đau', 'Giải pháp hỗ trợ giảm đau nhức cơ bắp, căng cứng cổ vai gáy và phục hồi cơ thể sau thời gian làm việc căng thẳng hoặc ngồi lâu.', 1, true, 'dich_vu');
INSERT INTO public.danh_muc_dich_vu (id, ten_danh_muc, mo_ta, thu_tu_hien_thi, an_hien, loai_danh_muc) VALUES (22, 'Thư Giãn & Giảm Stress', 'Các liệu pháp giúp thư giãn tinh thần, giảm căng thẳng, cải thiện giấc ngủ và mang lại cảm giác dễ chịu cho cơ thể.', 2, true, 'dich_vu');
INSERT INTO public.danh_muc_dich_vu (id, ten_danh_muc, mo_ta, thu_tu_hien_thi, an_hien, loai_danh_muc) VALUES (23, 'Kéo Giãn & Cải Thiện Vận Động', 'Hỗ trợ tăng độ linh hoạt của cơ thể, cải thiện tư thế, giảm căng cơ và giúp vận động thoải mái hơn trong sinh hoạt hằng ngày.', 3, true, 'dich_vu');
INSERT INTO public.danh_muc_dich_vu (id, ten_danh_muc, mo_ta, thu_tu_hien_thi, an_hien, loai_danh_muc) VALUES (24, 'Phục Hồi Chuyên Sâu', 'Các phương pháp phục hồi chuyên sâu giúp cơ thể tái tạo năng lượng, giảm mệt mỏi cơ bắp và tăng tốc quá trình hồi phục sau vận động hoặc làm việc cường độ cao.', 4, true, 'dich_vu');
INSERT INTO public.danh_muc_dich_vu (id, ten_danh_muc, mo_ta, thu_tu_hien_thi, an_hien, loai_danh_muc) VALUES (26, 'Cổ Vai Gáy Văn Phòng', 'Hỗ trợ giảm đau mỏi cổ vai gáy, căng cứng cơ và cải thiện khó chịu do ngồi làm việc lâu hoặc sai tư thế.', 1, true, 'goi');
INSERT INTO public.danh_muc_dich_vu (id, ten_danh_muc, mo_ta, thu_tu_hien_thi, an_hien, loai_danh_muc) VALUES (27, 'Thắt Lưng & Cột Sống', 'Giải pháp hỗ trợ giảm đau lưng, cải thiện vận động và phục hồi cột sống cho người ngồi nhiều hoặc ít vận động.', 2, true, 'goi');
INSERT INTO public.danh_muc_dich_vu (id, ten_danh_muc, mo_ta, thu_tu_hien_thi, an_hien, loai_danh_muc) VALUES (28, 'Chỉnh Tư Thế & Công Thái Học', 'Hỗ trợ cải thiện tư thế ngồi, cân bằng cơ thể và hạn chế các vấn đề cơ xương khớp thường gặp ở dân văn phòng.', 3, true, 'goi');
INSERT INTO public.danh_muc_dich_vu (id, ten_danh_muc, mo_ta, thu_tu_hien_thi, an_hien, loai_danh_muc) VALUES (29, 'Phục Hồi & Thư Giãn Toàn Thân', 'Các liệu trình giúp thư giãn cơ thể, giảm stress, phục hồi năng lượng và cải thiện trạng thái thể chất sau ngày dài làm việc.', 4, true, 'goi');
INSERT INTO public.danh_muc_dich_vu (id, ten_danh_muc, mo_ta, thu_tu_hien_thi, an_hien, loai_danh_muc) VALUES (30, 'Vận Động & Linh Hoạt Cơ Thể', 'Hỗ trợ tăng độ linh hoạt, giảm căng cơ và cải thiện khả năng vận động trong sinh hoạt hằng ngày.', 5, true, 'goi');
INSERT INTO public.danh_muc_dich_vu (id, ten_danh_muc, mo_ta, thu_tu_hien_thi, an_hien, loai_danh_muc) VALUES (31, 'Phục Hồi Tay & Cơ Chuyên Biệt', 'Hỗ trợ giảm đau và phục hồi các vùng cơ tay, cổ tay và khuỷu tay do làm việc lặp lại hoặc sử dụng máy tính nhiều.', 6, true, 'goi');
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('96761159-ab82-424c-84ec-7fd8bcf17101', 21, 'Giải phóng cơ thắt lưng', 'Tác động vào các nhóm cơ vùng lưng dưới bị căng cứng do ngồi lâu hoặc sai tư thế.', '•	Thư giãn cơ vùng thắt lưng 
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('0fb10eda-eb8d-4e1f-b7b4-5d6e7c86d24d', 21, 'Cân chỉnh tư thế', 'Hỗ trợ cải thiện tình trạng gù lưng, lệch vai và đầu chúi về trước.', '•	Điều chỉnh tư thế cơ thể 
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('d872710c-c322-4afd-abe9-d9b87c05a500', 21, 'Kéo giãn cột sống', 'Hỗ trợ kéo giãn vùng thắt lưng nhằm giảm áp lực lên đĩa đệm và cơ quanh cột sống.', '•	Hỗ trợ kéo giãn đúng kỹ thuật 
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('a2330734-cc8c-4321-920b-e29469cab240', 21, 'Trị liệu linh hoạt vai', 'Tăng độ linh hoạt vùng vai và lưng trên do ngồi làm việc lâu.
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('af901abf-d96a-4e88-9636-41abb9b52b32', 21, 'Giải phóng cơ căng cứng', 'Tác động vào các nhóm cơ bị co rút do ngồi sai tư thế kéo dài.', '•	Giải phóng điểm căng cơ 
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('550aa3f7-7859-410b-b123-64ecc436cc5a', 24, 'Massage Chân Phục Hồi', 'Dịch vụ Massage Chân Phục Hồi (Mã: ADD-FOOT-45)', 'Ấn huyệt phản xạ lòng bàn chân kết hợp massage giải co thắt cơ bắp chân và gót chân.', 30, 180000, NULL, 'hoat_dong', 0, NULL, 'bo_sung', true, '["Giảm đau mỏi gót chân gan bàn chân hiệu quả, giảm căng cứng cơ sinh đôi cẳng chân sau.", "Kích thích máu tĩnh mạch chi dưới lưu thông mượt mà tránh tê bì phù chân."]');
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('093eee29-9a02-4bb8-b06c-c18d0a3f96ea', 22, 'Massage Thư Giãn Phục Hồi', 'Dịch vụ Massage Thư Giãn Phục Hồi (Mã: ADD-MASSAGE-60)', 'Kỹ thuật viên thực hiện xoa bóp, vuốt miết toàn thân nhịp nhàng kết hợp tinh dầu dừa phân đoạn cao cấp giải tỏa cơ nông.', 60, 350000, NULL, 'hoat_dong', 0, NULL, 'bo_sung', true, '["Làm mềm cơ bắp mệt mỏi, xoa dịu các cơn đau cơ nhẹ sau những ngày ngồi làm việc sai tư thế.", "Thúc đẩy tuần hoàn máu và đem lại cảm giác nhẹ nhõm, dễ chịu tức thì."]');
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('05d6f5a2-f3ed-48c0-8819-02bb4bc3b30e', 22, 'Trị Liệu Tinh Dầu Thư Giãn', 'Dịch vụ Trị Liệu Tinh Dầu Thư Giãn (Mã: ADD-AROMA-45)', 'Massage vuốt lực nhẹ kết hợp tinh dầu oải hương hoặc sả chanh khuếch tán giải tỏa hệ phó giao cảm.', 60, 230000, NULL, 'hoat_dong', 0, NULL, 'bo_sung', true, '["Giải tỏa áp lực căng thẳng tinh thần, kích hoạt trạng thái thư giãn sâu của cơ thể.", "Cung cấp dưỡng chất thiên nhiên cao cấp làm dịu và phục hồi tế bào da."]');
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('b989c402-6d34-495a-adfb-00fcdf6683a5', 21, 'Trị liệu kéo giãn', 'Kéo giãn các nhóm cơ co rút.', '•	Hỗ trợ kéo giãn đúng kỹ thuật 
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('980e41d8-b362-4ebb-a262-28dd906c63b7', 23, 'Kéo Giãn Toàn Thân Chuyên Sâu', 'Dịch vụ Massage Đầu Cổ Vai Gáy (Mã: ADD-HEADNECK-40)', 'Day bấm cục bộ đai vai, cơ thang cổ và xoa bóp cơ da đầu xua tan mỏi đau tức thời.', 60, 200000, NULL, 'hoat_dong', 0, NULL, 'bo_sung', true, '["Giảm căng tức và cứng bả vai gáy do duy trì tư thế cúi gõ phím quá lâu.", "Cải thiện tuần hoàn động mạch brain/não bộ, giảm dứt điểm chứng đau đầu do stress mỏi mệt."]');
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('3793caaf-aac7-4fca-a205-e6304a54de3d', 21, 'Massage Đầu Cổ Vai Gáy', 'Dịch vụ Giác Hơi Phục Hồi (Mã: ADD-CUPPING-40)', 'Đặt giác ống thủy tinh nóng y khoa lên vùng cơ thắt lưng và vai dày bằng giác hơi lửa chân không truyền thống.', 30, 180000, NULL, 'hoat_dong', 0, NULL, 'bo_sung', true, '["Giảm căng tức và cứng bả vai gáy do duy trì tư thế cúi gõ phím quá lâu.", "Cải thiện tuần hoàn động mạch brain/não bộ, giảm dứt điểm chứng đau đầu do stress mỏi mệt."]');
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('4433e0c7-7b81-4e67-8798-42de478c8c2f', 21, 'Giác Hơi Phục Hồi', 'Dịch vụ Kéo Giãn Toàn Thân Chuyên Sâu (Mã: ADD-FULLSTR-45)', NULL, 30, 220000, NULL, 'hoat_dong', 0, NULL, 'bo_sung', true, '[]');
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('9898b2ab-6ca2-4077-a9ea-18dd2c47a6b2', 21, 'Hướng dẫn bài tập trị liệu', 'Hướng dẫn các bài tập hỗ trợ duy trì hiệu quả trị liệu và cải thiện tư thế.', 'Hướng dẫn các bài tập hỗ trợ duy trì hiệu quả trị liệu và cải thiện tư thế.', 15, 0, NULL, 'hoat_dong', 0, 'không có', 'chinh', false, '["Kích hoạt các nhóm cơ cần điều trị.", "Chỉnh sửa sai lệch tư thế lệch tận gốc.", "Duy trì kết quả trị liệu lâm sàng, chống tái phát đau."]');
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('bcc7490d-aa06-4002-9de7-aac60a39e5cc', 21, 'Massage trị liệu cơ sâu', 'Tác động chuyên sâu vào các nhóm cơ cổ, vai và gáy bị co cứng do ngồi làm việc lâu.', '•	Giải phóng điểm căng cơ 
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('c4b070a8-5326-4a8f-87e1-844a69e96830', 21, 'Kéo giãn vùng cổ', 'Hỗ trợ kéo giãn nhẹ nhàng vùng cổ nhằm giảm áp lực lên đốt sống cổ.', '•	Hỗ trợ kéo giãn đúng kỹ thuật 
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('85ef76d1-a234-4aed-9243-985f4bcc6d64', 21, 'Điện xung giảm đau', 'Sử dụng xung điện tần số thấp để hỗ trợ thư giãn cơ và giảm đau.', '•	Đặt điện cực đúng vùng điều trị 
INSERT INTO public.dich_vu (id, danh_muc_id, ten_dich_vu, mo_ta_ngan, mo_ta_chi_tiet, thoi_luong_phut, don_gia, hinh_anh_url, trang_thai, thu_tu_hien_thi, thiet_bi_yeu_cau, loai_dich_vu, hien_thi_website, loai_dich_vu_ho_tro) VALUES ('c5858904-162d-4a85-b809-3839ca866466', 21, 'Nhiệt trị liệu', 'Sử dụng nhiệt giúp thư giãn cơ và tăng tuần hoàn máu vùng cổ vai.', '•	Kiểm soát nhiệt độ an toàn 
